${SEP}.a 	EO(rec),
.
${SEP}vis 2${SEP}wq" $VI -e 'ex.c'

# Patch: term.c
SEP="$(printf '\001')"
QF=${QF-"$(printf 'vis 2\\\001q! 1')"}
EXINIT="rcm:|sc! \\\\${SEP}|vis 3${SEP}%;f> 		ret:
		ibuf_cnt = 1;
		ibuf_pos = 0;${SEP}??!${DBG:--5,+5p\\${SEP}p FAIL line 182\\${SEP}${QF}}${SEP};=
