			char buf[2];
			buf[0] = *ibuf;
			buf[1] = '\\\\0';
			ex_regput(xrec, buf, 1);
		}
.
${SEP}vis 2${SEP}wq" $VI -e 'term.c'

# Patch: vi.h
SEP="$(printf '\001')"
QF=${QF-"$(printf 'vis 2\\\001q! 1')"}
EXINIT="rcm:|sc! \\\\${SEP}|vis 3${SEP}%f> /\\\\* global variables \\\\*/${SEP}??!${DBG:--5,+5p\\${SEP}p FAIL line 426\\${SEP}${QF}}${SEP};=
